const express = require('express');
const router = express.Router();
const { getProjects, createProject } = require('./service');

router.get('/', getProjects);
router.post('/', createProject);
router.use('/:projectId', (req, res, next) => {
  req.projectId = req.params.projectId;
  next();
});
router.get('/:projectId/members', require('./members/routes'));
router.get('/:projectId/tasks', require('./tasks/routes'));

export default router;

const { randomUUID } = require('node:crypto');
const projects = {};

module.exports.getProjects = (req, res) => {
  res.json({ projects: Object.values(projects) });
};

module.exports.createProject = (req, res) => {
  if (!req.body.name) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Name is required' } });
  const projectId = randomUUID();
  projects[projectId] = { id: projectId, name: req.body.name };
  res.status(201).json({ project: projects[projectId] });
};

const express = require('express');
const router = express.Router({ mergeParams: true });
const { getMembers, createMember } = require('./service');

router.get('/', getMembers);
router.post('/', createMember);

export default router;

const express = require('express');
const router = express.Router({ mergeParams: true });
const { getTasks, createTask } = require('./service');

router.get('/', getTasks);
router.post('/', createTask);
router.patch('/:taskId', (req, res) => {
  const task = req.tasks[req.params.taskId];
  if (!task) return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  if (req.body.status && !['todo', 'done'].includes(req.body.status)) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Invalid status' } });
  task.status = req.body.status || task.status;
  res.json({ task });
});

export default router;

const tasks = {};
module.exports.getTasks = (req, res) => {
  const filteredTasks = Object.values(tasks).filter(task => req.query.status ? task.status === req.query.status : true);
  res.json({ tasks: filteredTasks });
};

module.exports.createTask = (req, res) => {
  const projectId = req.projectId;
  if (!projects[projectId]) return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  const taskId = randomUUID();
  tasks[taskId] = { id: taskId, status: req.body.status || 'todo' };
  projects[projectId].tasks = projects[projectId].tasks || {};
  projects[projectId].tasks[taskId] = tasks[taskId];
  res.status(201).json({ task: tasks[taskId] });
};

