const http = require('http');
const app = require('./app');

const server = http.createServer(app);

module.exports = app;

const { v4: uuidv4 } = require('uuid');
const projects = {};
const members = {};

export function createMember(projectId, memberData) {
  if (!memberData.userId || !memberData.role) throw new BadRequestError('UserId and role are required');
  const memberId = uuidv4();
  if (!projects[projectId]) return null;
  members[memberId] = { id: memberId, ...memberData };
  projects[projectId].members = projects[projectId].members || {};
  projects[projectId].members[memberId] = members[memberId];
  return members[memberId];
}

const express = require('express');
const router = express.Router({ mergeParams: true });
const { createComment } = require('./service');

router.post('/', async (req, res) => {
  const comment = await createComment(req.params.projectId, req.params.taskId, req.body);
  if (!comment) return sendError(res, 400, 'INVALID_DATA', 'Invalid data provided');
  res.status(201).json({ comment });
});

module.exports = router;

const { v4: uuidv4 } = require('uuid');
const projects = {};
const comments = {};
export function createComment(projectId, taskId, commentData) {
  if (!commentData.message) throw new BadRequestError('Message is required');
  const commentId = uuidv4();
  if (!projects[projectId] || !projects[projectId].tasks?.[taskId]) return null;
  comments[commentId] = { id: commentId, ...commentData };
  projects[projectId].tasks[taskId].comments = projects[projectId].tasks[taskId].comments || {};
  projects[projectId].tasks[taskId].comments[commentId] = comments[commentId];
  return comments[commentId];
}

const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};
exports.sendError = sendError;

const { randomUUID } = require("node:crypto");
module.exports = {
  generateId() {
    return randomUUID();
  }
};
